import type { ReactNode } from "react";
import { Header } from "@/components/headers/header";
import { BlogSidebar } from "@/components/layouts/blog-sidebar";
import { BlogHero } from "@/components/modules/blog/hero";
import { getBlogPosts } from "@/lib/blog";
import "@/styles/blog.css";

export default async function BlogLayout({ children }: { children: ReactNode }) {
  const posts = await getBlogPosts();

  return (
    <main className="min-h-screen relative">
      <Header variant="minimal" />
      <BlogHero />
      <div className="relative mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="lg:flex lg:gap-6">
          <BlogSidebar posts={posts} />
          <section className="flex-1 min-w-0 w-full lg:w-auto py-4">{children}</section>
        </div>
      </div>
    </main>
  );
}

import type { Metadata } from "next";
import { Suspense } from "react";
import { BlogPostComponent } from "@/components/modules/blog/post";
import { BlogPostListSkeleton } from "@/components/modules/blog/skeleton";
import { constructMetadata } from "@/config/metadata";
import { siteConfig } from "@/config/site-config";
import { type BlogPost, getBlogPosts } from "@/lib/blog";
import { formatDate } from "@/lib/utils/format-date";

export const metadata: Metadata = constructMetadata({
  title: "Blog - Latest Updates & Guides | Shipkit",
  description:
    "Stay up to date with the latest app development trends, tutorials, and best practices. Learn how to build better apps faster with Shipkit's expert guides and tips.",
});

// Enhanced BlogPost type with LogSpot-style fields
interface EnhancedBlogPost extends BlogPost {
  badge?: string;
  authors?: { name: string; avatar: string }[];
}

const BlogPage = async () => {
  const posts: BlogPost[] = await getBlogPosts();

  // Transform posts to LogSpot format with demo data
  const logSpotPosts: EnhancedBlogPost[] = posts.map((post, index) => ({
    ...post,
    badge: post.badge || `v1.${index.toString().padStart(2, "0")}`,
    authors: post.authors || [
      {
        name: siteConfig.creator.fullName,
        avatar: siteConfig.creator.avatar,
      },
    ],
  }));

  return (
    <div className="w-full">
      {/* Timeline container with proper spacing */}
      <Suspense fallback={<BlogPostListSkeleton count={3} />}>
        <div className="space-y-8">
          {logSpotPosts.map((post) => {
            const formattedDate = formatDate(post.publishedAt);

            return (
              <BlogPostComponent key={post.slug} post={post}>
                {post.description && <p>{post.description}</p>}
                {formattedDate && (
                  <p className="text-sm text-muted-foreground">Published on {formattedDate}</p>
                )}
              </BlogPostComponent>
            );
          })}
        </div>
      </Suspense>
    </div>
  );
};

export default BlogPage;

import { BlogPostListSkeleton } from "@/components/modules/blog/skeleton";

export default function Loading() {
  return <BlogPostListSkeleton count={5} />;
}

import { ArrowLeft } from "lucide-react";
import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";
import { MDXRemote } from "next-mdx-remote/rsc";
import { Suspense } from "react";
import remarkGfm from "remark-gfm";
import { BlogImage } from "@/components/modules/blog/image";
import { MobileToc } from "@/components/modules/blog/mobile-toc";
import { MobileTOCSkeleton, TOCSkeleton } from "@/components/modules/blog/skeleton";
import { TableOfContents } from "@/components/modules/blog/table-of-contents";
import { H1, H2, H3, H4, H5, H6 } from "@/components/modules/mdx/heading";
import { AskAiButtons } from "@/components/primitives/ask-ai-buttons";
import { buttonVariants } from "@/components/ui/button";
import { constructMetadata } from "@/config/metadata";
import { routes } from "@/config/routes";
import { siteConfig } from "@/config/site-config";
import { getBlogPosts } from "@/lib/blog";
import { cn } from "@/lib/utils";
import { extractHeadings, filterHeadingsByLevel } from "@/lib/utils/extract-headings";
import { formatDate, formatDateTimeAttribute } from "@/lib/utils/format-date";
import "@/styles/blog.css";

interface Props {
  params: Promise<{
    slug: string[];
  }>;
}

export async function generateStaticParams() {
  const posts = await getBlogPosts();

  return posts.map((post) => ({
    slug: post.slug.includes("/") ? post.slug.split("/") : [post.slug],
  }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const resolvedParams = await params;
  const slug = resolvedParams.slug.join("/");
  const posts = await getBlogPosts();
  const post = posts.find((post) => post.slug === slug);

  if (!post) {
    return constructMetadata({
      title: "Post Not Found | Shipkit Blog",
      description:
        "The blog post you're looking for could not be found. Browse our other articles for app development insights and guides.",
    });
  }

  // Build dynamic OG image URL using the existing /og route
  const ogUrl = new URL("/og", siteConfig.url);
  ogUrl.searchParams.set("title", post.title);
  if (post.description) ogUrl.searchParams.set("description", post.description);
  ogUrl.searchParams.set("url", siteConfig.url.replace(/https?:\/\//, ""));

  return constructMetadata({
    title: `${post.title} | Shipkit Blog`,
    description:
      post.description ||
      "Read this comprehensive guide on app development best practices, tips, and insights from the Shipkit team.",
    images: [
      {
        url: ogUrl.toString(),
        width: siteConfig.metadata.openGraph.imageWidth,
        height: siteConfig.metadata.openGraph.imageHeight,
        alt: post.title,
      },
    ],
    openGraph: {
      title: post.title,
      description: post.description,
      type: "article",
      publishedTime: post.publishedAt,
      authors: post.author ? [post.author] : undefined,
    },
  });
}

const BlogPostPage = async ({ params }: Props) => {
  const resolvedParams = await params;
  const slug = resolvedParams.slug.join("/");
  const posts = await getBlogPosts();
  const post = posts.find((post) => post.slug === slug);

  if (!post) {
    notFound();
  }

  // Extract headings from content for TOC
  const allHeadings = extractHeadings(post.content);
  const tocHeadings = filterHeadingsByLevel(allHeadings, 2, 4); // Show h2-h4 in TOC

  // Safe date formatting
  const dateTimeAttr = formatDateTimeAttribute(post.publishedAt);
  const displayDate = formatDate(post.publishedAt);

  // MDX components with custom headings
  const components = {
    h1: H1,
    h2: H2,
    h3: H3,
    h4: H4,
    h5: H5,
    h6: H6,
  };

  return (
    <div className="relative w-full">
      {/* Back button */}
      <Link
        href={routes.blog}
        className={cn(
          buttonVariants({ variant: "ghost", size: "sm" }),
          "mb-8 h-auto p-0 text-muted-foreground hover:text-foreground"
        )}
      >
        <ArrowLeft className="mr-2 h-4 w-4" />
        Back to Blog
      </Link>

      <div className="flex gap-8">
        {/* Main content */}
        <article className="flex-1 min-w-0">
          {/* Mobile TOC */}
          <Suspense fallback={<MobileTOCSkeleton />}>
            <MobileToc headings={tocHeadings} />
          </Suspense>

          {/* Header section */}
          <header className="flex flex-col gap-4 border-b pb-8 mb-8">
            <h1 className="scroll-m-20 text-4xl font-bold tracking-tight lg:text-5xl">
              {post.title}
            </h1>
            {post.description && (
              <p className="text-xl text-muted-foreground leading-7">{post.description}</p>
            )}

            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                {post.author && <span className="font-medium text-foreground">{post.author}</span>}
                {displayDate && (
                  <>
                    <span>•</span>
                    <time dateTime={dateTimeAttr}>{displayDate}</time>
                  </>
                )}
              </div>

              {post.categories && post.categories.length > 0 && (
                <div className="flex flex-wrap gap-2">
                  {post.categories.map((category) => (
                    <Link
                      key={category}
                      href={`/blog/categories/${encodeURIComponent(category)}`}
                      className={buttonVariants({
                        variant: "secondary",
                        size: "sm",
                      })}
                    >
                      {category}
                    </Link>
                  ))}
                </div>
              )}
            </div>
          </header>

          {/* Content section */}
          <div className="prose prose-neutral dark:prose-invert max-w-none">
            {/* Featured image */}
            {post.image && (
              <BlogImage src={post.image} alt={post.title} className="mb-8" priority={true} />
            )}
            <MDXRemote
              source={post.content}
              components={components}
              options={{ mdxOptions: { remarkPlugins: [remarkGfm] } }}
            />
          </div>

          {/* AI summary buttons */}
          <div className="mt-12 pt-8 border-t">
            <p className="text-sm text-muted-foreground mb-3">Read with AI</p>
            <AskAiButtons
              goal={`Summarize this article: ${post.title}`}
              content={[post.title, post.description, post.content].filter(Boolean).join("\n\n")}
            />
          </div>
        </article>

        {/* Table of Contents - Now properly sticky */}
        {tocHeadings.length > 0 && (
          <aside className="hidden lg:block w-64 shrink-0">
            <div className="sticky top-8 max-h-[calc(100vh-4rem)] overflow-y-auto">
              <Suspense fallback={<TOCSkeleton />}>
                <TableOfContents headings={tocHeadings} />
              </Suspense>
            </div>
          </aside>
        )}
      </div>
    </div>
  );
};

export default BlogPostPage;

import { BlogPostSkeleton } from "@/components/modules/blog/skeleton";

export default function Loading() {
  return <BlogPostSkeleton />;
}

import { Link } from "@/components/primitives/link";
import { Badge } from "@/components/ui/badge";
import { getBlogCategories, getBlogPosts } from "@/lib/blog";
import { cn } from "@/lib/utils";

interface Props {
  searchParams: Promise<Record<string, string | string[] | undefined>>;
}

export default async function CategoriesPage({ searchParams }: Props) {
  const params = await searchParams;
  const posts = await getBlogPosts();
  const categories = getBlogCategories(posts);
  const selectedCategory = typeof params.category === "string" ? params.category : undefined;

  // Filter categories if a category is selected
  const filteredCategories = selectedCategory
    ? categories.filter((category) => category.name === selectedCategory)
    : categories;

  return (
    <div className="container py-8">
      <div className="mb-8 flex items-center justify-between">
        <h1 className="text-3xl font-bold">Blog Categories</h1>
        {selectedCategory && (
          <Link
            href="/blog/categories"
            className="text-sm text-muted-foreground hover:text-foreground"
          >
            Clear filter
          </Link>
        )}
      </div>

      <div className="mb-8 flex flex-wrap gap-2">
        {categories.map((category) => (
          <Link key={category.name} href={`/blog/categories/${encodeURIComponent(category.name)}`}>
            <Badge
              variant={category.name === selectedCategory ? "default" : "secondary"}
              className="hover:bg-secondary/80"
            >
              {category.name} ({category.posts.length})
            </Badge>
          </Link>
        ))}
      </div>

      <div className="grid gap-8">
        {filteredCategories.map((category) => (
          <div key={category.name} className="space-y-4">
            <h2 className="text-2xl font-semibold">{category.name}</h2>
            <div className="grid gap-4">
              {category.posts.map((post) => (
                <Link
                  key={post.slug}
                  href={`/blog/${post.slug}`}
                  className={cn("block rounded-lg border p-4 transition-colors hover:bg-muted")}
                >
                  <h3 className="mb-2 font-medium">{post.title}</h3>
                  {post.description && (
                    <p className="text-sm text-muted-foreground">{post.description}</p>
                  )}
                </Link>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { Link } from "@/components/primitives/link";
import { Badge } from "@/components/ui/badge";
import { getBlogCategories, getBlogPosts } from "@/lib/blog";
import { cn } from "@/lib/utils";

// Generate static paths for all blog categories
export async function generateStaticParams() {
  const posts = await getBlogPosts();
  const categories = getBlogCategories(posts);

  return categories.map((cat) => ({
    // URL-encode the category name for the param
    category: encodeURIComponent(cat.name),
  }));
}

// Use params for route segments - params is now a Promise in Next.js 15
interface CategoryPageProps {
  params: Promise<{
    category: string;
  }>;
}

// Note: The component signature is updated to use params as Promise
export default async function CategoryPage({ params }: CategoryPageProps) {
  // Await the params Promise
  const resolvedParams = await params;
  // Decode the category name from the URL parameter
  const category = decodeURIComponent(resolvedParams.category);

  const posts = await getBlogPosts();
  const categories = getBlogCategories(posts);
  const selectedCategory = category;

  // Filter categories if a category is selected
  const filteredCategories = selectedCategory
    ? categories.filter((cat) => cat.name === selectedCategory)
    : categories;

  return (
    <div className="container py-8">
      <h1 className="text-3xl font-bold">{selectedCategory || "All Categories"}</h1>
      <div className="mb-8 flex flex-wrap gap-2">
        {categories.map((cat) => (
          <Link key={cat.name} href={`/blog/categories/${encodeURIComponent(cat.name)}`}>
            <Badge
              variant={cat.name === selectedCategory ? "default" : "secondary"}
              className="hover:bg-secondary/80"
            >
              {cat.name} ({cat.posts.length})
            </Badge>
          </Link>
        ))}
      </div>

      <div className="grid gap-8">
        {filteredCategories.map((cat) => (
          <div key={cat.name} className="space-y-4">
            <h2 className="text-2xl font-semibold">{cat.name}</h2>
            <div className="grid gap-4">
              {cat.posts.map((post) => (
                <Link
                  key={post.slug}
                  href={`/blog/${post.slug}`}
                  className={cn("block rounded-lg border p-4 transition-colors hover:bg-muted")}
                >
                  <h3 className="mb-2 font-medium">{post.title}</h3>
                  {post.description && (
                    <p className="text-sm text-muted-foreground">{post.description}</p>
                  )}
                </Link>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import { AuthorProfile } from "@/components/modules/blog/author-profile";
import { Link } from "@/components/primitives/link";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import {
  authorUtils,
  type BlogAuthor,
  getActiveAuthors,
  getAuthorById,
  getAuthorByName,
} from "@/config/blog-authors";
import { constructMetadata } from "@/config/metadata";
import { routes } from "@/config/routes";
import { getBlogPosts } from "@/lib/blog";
import { formatDate } from "@/lib/utils/format-date";

interface Props {
  params: Promise<{
    author: string;
  }>;
}

export async function generateStaticParams() {
  const posts = await getBlogPosts();
  const activeAuthors = getActiveAuthors();
  const authorIds = new Set<string>();

  // Add author IDs from active authors
  activeAuthors.forEach((author) => authorIds.add(author.id));

  // Add legacy author names that have posts
  posts.forEach((post) => {
    if (post.author) {
      const author = getAuthorByName(post.author);
      authorIds.add(author.id);
    }
    if (post.authorObject) {
      authorIds.add(post.authorObject.id);
    }
    if (post.authorObjects) {
      post.authorObjects.forEach((author) => authorIds.add(author.id));
    }
  });

  return Array.from(authorIds).map((authorId) => ({
    author: encodeURIComponent(authorId),
  }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const resolvedParams = await params;
  const authorId = decodeURIComponent(resolvedParams.author);
  const author = getAuthorById(authorId);
  const displayName = authorUtils.getDisplayName(author);

  return constructMetadata({
    title: `Posts by ${displayName} | Shipkit Blog`,
    description: `Read all blog posts written by ${displayName}. Discover insights, tutorials, and best practices for app development.`,
  });
}

export default async function AuthorPage({ params }: Props) {
  const resolvedParams = await params;
  const authorId = decodeURIComponent(resolvedParams.author);
  const author = getAuthorById(authorId);
  const displayName = authorUtils.getDisplayName(author);
  const posts = await getBlogPosts();

  // Filter posts by author (support both legacy and new systems)
  const authorPosts = posts.filter((post) => {
    // Check new author system first
    if (post.authorObject && post.authorObject.id === authorId) {
      return true;
    }
    if (post.authorObjects?.some((a) => a.id === authorId)) {
      return true;
    }
    // Check legacy author system
    if (post.author) {
      const legacyAuthor = getAuthorByName(post.author);
      return legacyAuthor.id === authorId;
    }
    return false;
  });

  if (authorPosts.length === 0) {
    return (
      <div className="container py-8">
        <h1 className="text-3xl font-bold mb-4">Author Not Found</h1>
        <p className="text-muted-foreground mb-4">No posts found for author "{displayName}".</p>
        <Link href={routes.blog} className="text-blue-600 hover:text-blue-800 underline">
          ← Back to Blog
        </Link>
      </div>
    );
  }

  return (
    <div className="w-full">
      <div className="mb-8">
        <div className="flex flex-col lg:flex-row gap-8 mb-8">
          <div className="lg:w-1/3">
            <AuthorProfile author={author} postCount={authorPosts.length} />
          </div>
          <div className="lg:w-2/3">
            <h1 className="text-3xl font-bold mb-2">Posts by {displayName}</h1>
            <p className="text-muted-foreground">
              {authorPosts.length} post{authorPosts.length !== 1 ? "s" : ""} found
            </p>
          </div>
        </div>
      </div>

      <div className="grid gap-6">
        {authorPosts.map((post) => (
          <Card key={post.slug} className="transition-colors hover:bg-muted/50">
            <CardHeader>
              {post.categories && post.categories.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-2">
                  {post.categories.map((category) => (
                    <Link key={category} href={`/blog/categories/${encodeURIComponent(category)}`}>
                      <Badge variant="secondary">{category}</Badge>
                    </Link>
                  ))}
                </div>
              )}
              <Link href={`/blog/${post.slug}`} className="group">
                <CardTitle className="group-hover:underline">{post.title}</CardTitle>
                {post.description && (
                  <CardDescription className="mt-2">{post.description}</CardDescription>
                )}
              </Link>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                {post.publishedAt && (
                  <time dateTime={post.publishedAt}>{formatDate(post.publishedAt)}</time>
                )}
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}

export { AuthorByline, AuthorProfile } from "./author-profile";
export { BlogAuthors } from "./authors";
export { BlogBadge } from "./badge";
export { BlogHero } from "./hero";
export { BlogImage } from "./image";
export { MobileToc } from "./mobile-toc";
export { BlogPostComponent } from "./post";
export {
  BlogAuthorSkeleton,
  BlogCategoriesSkeleton,
  BlogPostListItemSkeleton,
  BlogPostListSkeleton,
  BlogPostSkeleton,
  MobileTOCSkeleton,
  TOCSkeleton,
} from "./skeleton";
export { TableOfContents } from "./table-of-contents";

import Image from "next/image";
import type React from "react";
import { Icon } from "@/components/assets/icon";
import { Link } from "@/components/primitives/link";
import { siteConfig } from "@/config/site-config";
import logoImage from "@/public/logo.png";
export const BlogHero = () => {
  return (
    <header className="py-12 px-4 sm:px-6 lg:px-8">
      <div className="relative mx-auto max-w-[37.5rem] pt-20 text-center pb-20">
        <div className="flex items-center justify-center space-x-3">
          {/* <Icon name="logo" className="w-10 h-10" /> */}
          <Image src={logoImage} alt="Shipkit" width={100} height={100} priority />
          <h1 className="text-4xl font-extrabold tracking-tight text-primary/90 sm:text-5xl">
            {siteConfig.name} Blog
