import type React from "react";
import { BlogImage } from "@/components/modules/blog/image";
import { Link } from "@/components/primitives/link";
import { authorUtils, type BlogAuthor, getAuthorByName } from "@/config/blog-authors";
import type { BlogPost } from "@/lib/blog";
import { formatDateForBlog } from "@/lib/utils/format-date";
import { BlogAuthors } from "./authors";
import { BlogBadge } from "./badge";

interface BlogPostProps {
  post: BlogPost & {
    badge?: string;
    authors?: { name: string; avatar: string }[]; // Legacy support
    authorObjects?: BlogAuthor[]; // New structured authors
    publishedAt?: string | Date;
    image?: string;
  };
  children: React.ReactNode;
}

export const BlogPostComponent = ({ post, children }: BlogPostProps) => {
  const displayDate = formatDateForBlog(post.publishedAt);

  // Determine which authors to display (prefer new system)
  const authorsToDisplay = post.authorObjects || post.authors;
  const singleAuthor = post.authorObject || (post.author ? { name: post.author } : null);

  return (
    <article className="md:flex">
      <h2 className="content-date h-full mt-px">
        <span>{displayDate}</span>
      </h2>
      <div className="content-block">
        <div className="feed-border" />
        <div className="feed-dot" />
        {post.badge && (
          <BlogBadge label={post.badge} className="absolute -top-6 right-0 md:static mb-4" />
        )}
        <Link href={`/blog/${post.slug}`} className="group">
          <h1 className="text-xl sm:text-3xl font-bold mb-4 group-hover:underline cursor-pointer">
            {post.title}
          </h1>
        </Link>
        {post.image && (
          <BlogImage
            src={post.image}
            alt={post.title}
            className="mb-6 blog-image"
            priority={false}
          />
        )}
        <div className="document">{children}</div>

        {/* Multiple authors */}
        {authorsToDisplay && authorsToDisplay.length > 0 && (
          <BlogAuthors authors={authorsToDisplay} />
        )}

        {/* Single author link (new system) */}
        {singleAuthor && post.authorObject && (
          <div className="mt-4 text-sm text-muted-foreground">
            By{" "}
            <Link
              href={authorUtils.getAuthorUrl(post.authorObject)}
              className="text-foreground hover:underline font-medium"
            >
              {authorUtils.getDisplayName(post.authorObject)}
            </Link>
          </div>
        )}

        {/* Single author link (legacy support) */}
        {singleAuthor && !post.authorObject && post.author && (
          <div className="mt-4 text-sm text-muted-foreground">
            By{" "}
            <Link
              href={authorUtils.getAuthorUrl(getAuthorByName(post.author))}
              className="text-foreground hover:underline font-medium"
            >
              {authorUtils.getDisplayName(getAuthorByName(post.author))}
            </Link>
          </div>
        )}
      </div>
    </article>
  );
};

import Image from "next/image";
import type React from "react";
import { Link } from "@/components/primitives/link";
import { authorUtils, type BlogAuthor } from "@/config/blog-authors";

// Legacy author interface for backward compatibility
interface LegacyAuthor {
  name: string;
  avatar: string;
}

interface BlogAuthorsProps {
  authors: (BlogAuthor | LegacyAuthor)[];
}

/**
 * Check if author is a BlogAuthor (new system) or LegacyAuthor
 */
function isBlogAuthor(author: BlogAuthor | LegacyAuthor): author is BlogAuthor {
  return "id" in author;
}

export const BlogAuthors = ({ authors }: BlogAuthorsProps) => {
  if (!authors || authors.length === 0) return null;

  return (
    <div className="flex -space-x-2 relative z-0 mt-6" role="group" aria-label="Article authors">
      {authors.map((author, i) => {
        const isNewAuthor = isBlogAuthor(author);
        const displayName = isNewAuthor ? authorUtils.getDisplayName(author) : author.name;
        const authorUrl = isNewAuthor ? authorUtils.getAuthorUrl(author) : null;

        const imageElement = (
          <Image
            className="relative inline-block h-8 w-8 rounded-full ring-2 ring-white transition-transform hover:scale-110"
            style={{ zIndex: authors.length - i }}
            src={author.avatar}
            alt={displayName}
            width={32}
            height={32}
            title={displayName}
          />
        );

        // If new author system with URL, wrap in link
        if (authorUrl) {
          return (
            <Link
              key={isNewAuthor ? author.id : `legacy-${i}`}
              href={authorUrl}
              className="focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 rounded-full"
              aria-label={`View ${displayName}'s profile`}
            >
              {imageElement}
            </Link>
          );
        }

        // Legacy author or no URL
        return (
          <div key={isNewAuthor ? author.id : `legacy-${i}`} className="focus:outline-none">
            {imageElement}
          </div>
        );
      })}
    </div>
  );
};

