"use client";

import { type KeyboardEvent, useCallback, useEffect, useState } from "react";
import { ErrorBoundary, type FallbackProps } from "react-error-boundary";
import { cn } from "@/lib/utils";
import { TOCSkeleton } from "./skeleton";

interface Heading {
  id: string;
  text: string;
  level: number;
}

interface TableOfContentsProps {
  headings: Heading[];
}

function TableOfContentsInner({ headings }: TableOfContentsProps) {
  const [activeId, setActiveId] = useState<string>("");

  const handleClick = useCallback((id: string) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: "smooth", block: "start" });
      // Focus management for accessibility
      element.focus({ preventScroll: true });
    }
  }, []);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent<HTMLButtonElement>, id: string) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        handleClick(id);
      }
    },
    [handleClick]
  );

  useEffect(() => {
    // Guard against environments where IntersectionObserver isn't available
    if (!window.IntersectionObserver) {
      console.warn("IntersectionObserver not available, TOC active state disabled");
      return;
    }

    let observer: IntersectionObserver;

    try {
      observer = new IntersectionObserver(
        (entries) => {
          // Find the first heading that's visible (intersecting)
          const visibleHeading = entries.find((entry) => entry.isIntersecting);
          if (visibleHeading) {
            setActiveId(visibleHeading.target.id);
          }
        },
        {
          rootMargin: "-80px 0px -80% 0px", // Trigger when heading is near top of viewport
          threshold: 0.1,
        }
      );

      // Observe all headings with error handling
      headings.forEach(({ id }) => {
        try {
          const element = document.getElementById(id);
          if (element) {
            observer.observe(element);
          }
        } catch (error) {
          console.warn(`Failed to observe heading with id: ${id}`, error);
        }
      });
    } catch (error) {
      console.error("Failed to create IntersectionObserver:", error);
    }

    return () => {
      if (observer) {
        observer.disconnect();
      }
    };
  }, [headings]);

  if (headings.length === 0) {
    return null;
  }

  return (
    <aside className="blog-toc" role="complementary" aria-label="Table of contents">
      <div className="px-4 py-3 border-b border-border">
        <h4
          className="font-medium text-sm text-muted-foreground uppercase tracking-wide"
          id="toc-heading"
        >
          Table of Contents
        </h4>
      </div>
      <nav className="p-4" role="navigation" aria-labelledby="toc-heading">
        <ul className="space-y-1" role="list">
          {headings.map(({ id, text, level }, index) => (
            <li key={id} role="listitem">
              <button
                type="button"
                onClick={() => handleClick(id)}
                onKeyDown={(e) => handleKeyDown(e, id)}
                className={cn(
                  "block w-full text-left text-sm transition-colors duration-200 py-1.5 px-2 rounded-md hover:bg-muted/60 focus:bg-muted/60 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1",
                  "toc-link",
                  activeId === id && "active bg-muted/80 text-foreground font-medium",
                  level === 2 && "pl-2",
                  level === 3 && "pl-6",
                  level === 4 && "pl-10",
                  level > 4 && "pl-14"
                )}
                aria-current={activeId === id ? "location" : undefined}
                aria-label={`Go to ${text} (heading level ${level})`}
                tabIndex={0}
              >
                <span className="block truncate">{text}</span>
              </button>
            </li>
          ))}
        </ul>
      </nav>
    </aside>
  );
}

/**
 * Error fallback component for TOC
 */
function TOCErrorFallback({ error, resetErrorBoundary }: FallbackProps) {
  return (
    <div className="blog-toc">
      <div className="px-4 py-3 border-b border-border">
        <h4 className="font-medium text-sm text-muted-foreground uppercase tracking-wide">
          Table of Contents
        </h4>
      </div>
      <div className="p-4 text-center">
        <p className="text-sm text-muted-foreground mb-2">Failed to load table of contents</p>
        {error instanceof Error && (
          <p className="text-xs text-muted-foreground mb-3">{error.message}</p>
        )}
        <button onClick={resetErrorBoundary} className="text-xs text-primary hover:underline">
          Try again
        </button>
      </div>
    </div>
  );
}

/**
 * Table of Contents component with error boundary
 */
export function TableOfContents({ headings }: TableOfContentsProps) {
  return (
    <ErrorBoundary
      FallbackComponent={TOCErrorFallback}
      onError={(error, errorInfo) => {
        console.error("TOC Error:", error, errorInfo);
      }}
    >
      <TableOfContentsInner headings={headings} />
    </ErrorBoundary>
  );
}

"use client";

import { ChevronDown, List } from "lucide-react";
import { type KeyboardEvent, useCallback, useState } from "react";
import { ErrorBoundary, type FallbackProps } from "react-error-boundary";
import { Button } from "@/components/ui/button";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import type { Heading } from "@/lib/utils/extract-headings";
import { MobileTOCSkeleton } from "./skeleton";
import { TableOfContents } from "./table-of-contents";

interface MobileTocProps {
  headings: Heading[];
}

function MobileTocInner({ headings }: MobileTocProps) {
  const [isOpen, setIsOpen] = useState(false);

  const handleToggle = useCallback(() => {
    setIsOpen(!isOpen);
  }, [isOpen]);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent<HTMLButtonElement>) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        handleToggle();
      }
    },
    [handleToggle]
  );

  if (headings.length === 0) {
    return null;
  }

  return (
    <div className="xl:hidden mb-8" role="complementary" aria-label="Mobile table of contents">
      <Collapsible open={isOpen} onOpenChange={setIsOpen}>
        <CollapsibleTrigger asChild>
          <Button
            variant="outline"
            className="w-full justify-between focus:ring-2 focus:ring-ring focus:ring-offset-2"
            onClick={handleToggle}
            onKeyDown={handleKeyDown}
            aria-expanded={isOpen}
            aria-controls="mobile-toc-content"
            aria-label={`${isOpen ? "Collapse" : "Expand"} table of contents`}
          >
            <div className="flex items-center gap-2">
              <List className="h-4 w-4" aria-hidden="true" />
              <span>Table of Contents</span>
            </div>
            <ChevronDown
              className={`h-4 w-4 transition-transform ${isOpen ? "rotate-180" : ""}`}
              aria-hidden="true"
            />
          </Button>
        </CollapsibleTrigger>
        <CollapsibleContent className="mt-4" id="mobile-toc-content" aria-hidden={!isOpen}>
          <div className="border rounded-lg p-4 bg-muted/30">
            <TableOfContents headings={headings} />
          </div>
        </CollapsibleContent>
      </Collapsible>
    </div>
  );
}

/**
 * Error fallback component for Mobile TOC
 */
function MobileTocErrorFallback({ error, resetErrorBoundary }: FallbackProps) {
  return (
    <div className="xl:hidden mb-8">
      <div className="border rounded-lg p-4 bg-muted/30">
        <div className="text-center">
          <p className="text-sm text-muted-foreground mb-2">Failed to load table of contents</p>
          {error instanceof Error && (
            <p className="text-xs text-muted-foreground mb-3">{error.message}</p>
          )}
          <button
            onClick={resetErrorBoundary}
            className="text-xs text-primary hover:underline focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1"
          >
            Try again
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * Mobile Table of Contents component with error boundary
 */
export const MobileToc = ({ headings }: MobileTocProps) => {
  return (
    <ErrorBoundary
      FallbackComponent={MobileTocErrorFallback}
      onError={(error, errorInfo) => {
        console.error("Mobile TOC Error:", error, errorInfo);
      }}
    >
      <MobileTocInner headings={headings} />
    </ErrorBoundary>
  );
};

